import{_ as a,c as t,o as r,aj as o}from"./chunks/framework.BlveriQe.js";const g=JSON.parse('{"title":"Interface: DatabaseTypeConfigInfo","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/DatabaseTypeConfigInfo.md","filePath":"reference/js-bao-wss-client/api/interfaces/DatabaseTypeConfigInfo.md"}'),d={name:"reference/js-bao-wss-client/api/interfaces/DatabaseTypeConfigInfo.md"};function s(c,e,n,i,l,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / DatabaseTypeConfigInfo</p><h1 id="interface-databasetypeconfiginfo" tabindex="-1">Interface: DatabaseTypeConfigInfo <a class="header-anchor" href="#interface-databasetypeconfiginfo" aria-label="Permalink to “Interface: DatabaseTypeConfigInfo”">​</a></h1><p>A serialized database-type-configuration row, as returned by the <code>databases/types</code> endpoints.</p><p>Database type configs control schema-less database behavior for documents tagged with a particular <code>databaseType</code>: which rule set governs access, which CEL-driven <code>triggers</code> run on writes, and how <code>metadataAccess</code> is gated.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="appid" tabindex="-1">appId <a class="header-anchor" href="#appid" aria-label="Permalink to “appId”">​</a></h3><blockquote><p><strong>appId</strong>: <code>string</code></p></blockquote><hr><h3 id="createdat" tabindex="-1">createdAt <a class="header-anchor" href="#createdat" aria-label="Permalink to “createdAt”">​</a></h3><blockquote><p><strong>createdAt</strong>: <code>string</code></p></blockquote><hr><h3 id="createdby" tabindex="-1">createdBy <a class="header-anchor" href="#createdby" aria-label="Permalink to “createdBy”">​</a></h3><blockquote><p><strong>createdBy</strong>: <code>string</code></p></blockquote><hr><h3 id="databasetype" tabindex="-1">databaseType <a class="header-anchor" href="#databasetype" aria-label="Permalink to “databaseType”">​</a></h3><blockquote><p><strong>databaseType</strong>: <code>string</code></p></blockquote><hr><h3 id="metadataaccess" tabindex="-1"><s>metadataAccess</s> <a class="header-anchor" href="#metadataaccess" aria-label="Permalink to “metadataAccess”">​</a></h3><blockquote><p><strong>metadataAccess</strong>: <code>string</code> | <code>null</code></p></blockquote><p>CEL expression evaluated to decide whether the caller can read database metadata. <code>null</code> when not configured.</p><h4 id="deprecated" tabindex="-1">Deprecated <a class="header-anchor" href="#deprecated" aria-label="Permalink to “Deprecated”">​</a></h4><p>Prefer resource metadata categories (issue #1420). This single expression gates read AND update of the database CEL context, so granting read also grants update. Declare a metadata category in <a href="#metadatamanifest">metadataManifest</a> — a category has separate <code>readRule</code>/<code>writeRule</code> — and read it from CEL as <code>md.self.&lt;category&gt;.&lt;key&gt;</code>. See the migration recipe in <code>databases.md</code>. The field keeps working; the runtime gate is unchanged.</p><hr><h3 id="metadatamanifest" tabindex="-1">metadataManifest <a class="header-anchor" href="#metadatamanifest" aria-label="Permalink to “metadataManifest”">​</a></h3><blockquote><p><strong>metadataManifest</strong>: <a href="./DeclaredMetadataManifest.html"><code>DeclaredMetadataManifest</code></a> | <code>null</code></p></blockquote><p>The declared-access manifest for this type&#39;s CEL rules (issue #1420), returned parsed. <code>null</code> when none is set. Declaring a category here is the prerequisite for reading <code>md.self.&lt;category&gt;.&lt;key&gt;</code> from this type&#39;s rules — i.e. for migrating a <code>metadataAccess</code> gate to a metadata category.</p><hr><h3 id="modifiedat" tabindex="-1">modifiedAt <a class="header-anchor" href="#modifiedat" aria-label="Permalink to “modifiedAt”">​</a></h3><blockquote><p><strong>modifiedAt</strong>: <code>string</code></p></blockquote><hr><h3 id="rulesetid" tabindex="-1">ruleSetId <a class="header-anchor" href="#rulesetid" aria-label="Permalink to “ruleSetId”">​</a></h3><blockquote><p><strong>ruleSetId</strong>: <code>string</code> | <code>null</code></p></blockquote><hr><h3 id="triggers" tabindex="-1">triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to “triggers”">​</a></h3><blockquote><p><strong>triggers</strong>: <code>Record</code>&lt;<code>string</code>, <a href="./ModelRulesInfo.html"><code>ModelRulesInfo</code></a>&gt; | <code>null</code></p></blockquote><p>Trigger rules keyed by model name (e.g. <code>{ Task: { triggers: [{ on: &quot;create&quot;, set: { ... } }] } }</code>). <code>null</code> when no triggers are configured. Reuses <code>ModelRulesInfo</code> from <code>ruleSetsApi</code> — the same per-model rules shape rule sets carry (#1544).</p>',38)])])}const f=a(d,[["render",s]]);export{g as __pageData,f as default};
